class Solution {
    private Node firstNode = null;
    private Node secondNode = null;
    private Node prevNode = new Node(Integer.MIN_VALUE);

    private void traverse(Node root) {
        if (root == null) return;

        traverse(root.left);

        if (firstNode == null && prevNode.val >= root.val) {
            firstNode = prevNode;
        }

        if (firstNode != null && prevNode.val >= root.val) {
            secondNode = root;
        }

        prevNode = root;

        traverse(root.right);
    }

    public Node recoverBST(Node root) {
        traverse(root);
        int temp = firstNode.val;
        firstNode.val = secondNode.val;
        secondNode.val = temp;
        return root;
    }

    public Node lcaInBST(Node root, int p, int q) {
        if (root == null) return null;
        if (root.val > p && root.val > q) {
            return lcaInBST(root.left, p, q);
        }
        if (root.val < p && root.val < q) {
            return lcaInBST(root.right, p, q);
        }
        return root;
    }
}

