function findLCA(root, X, Y) {
    if (!root) return null;

    let current = root;

    while (current) {
        if (current.val > X && current.val > Y) {
            current = current.left;
        } else if (current.val < X && current.val < Y) {
            current = current.right;
        } else {
            return current.val;
        }
    }

    return null;
}
